<template>
    <div class="container">
        <h1>Formulario Estudiantes</h1>
        
        <form id="student-form" @submit.prevent="guardar">
            <div class="form-group">
                <label for="codigo">Código</label>
                <input type="text" id="codigo" name="codigo" required v-model="codigo" />
            </div>
            <div class="form-group">
                <label for="nombre">Nombre</label>
                <input type="text" id="nombre" name="nombre" required v-model="nombre"/>
            </div>
            <div class="form-group">
                <label for="apellido">Apellido</label>
                <input type="text" id="apellido" name="apellido" required v-model="apellido"/>
            </div>
            <div class="form-group">
                <label for="edad">Edad</label>
                <input type="text" id="edad" name="edad" required v-model="edad"/>
            </div>

            <button type="submit">Guargar</button><br>
            <button type="button" @click="eliminar">Eliminar</button><br>
            <button type="button" @click="actualizar">Actualizar</button><br>
            <button type="button" @click="consultar">Consultar</button><br>

        </form>

    </div>

</template>

<script>
    import axios from 'axios';

    export default{
        data(){
            return{
                codigo:"",
                nombre:"",
                apellido:"",
                edad: "",
            };
        },

        methods:{
            guardar(){
                axios
                .post("https://ejemplo3-production-817c.up.railway.app/api/estudiantes/", {
                    codigo: this.codigo,
                    nombre: this.nombre,
                    apellido: this.apellido,
                    edad: this.edad
                })
                .then((Response)=>{
                    console.log("Estudiante registrado con éxito", Response.data);
                    alert("éxito");
                    this.codigo='';
                    this.nombre='';
                    this.apellido='';
                    this.edad='';
                })
                .catch((error)=>{
                    console.error("Error al registrar el estudiante", error);
                    alert("Error");
                });


            }, 

            consultar(){
                axios.get("https://ejemplo3-production-817c.up.railway.app/api/estudiantes/"+this.codigo)
                .then((Response)=>{
                    this.nombre = Response.data.nombre;
                    this.apellido = Response.data.apellido;
                    this.edad = Response.data.edad;
                    
                })
                .catch((error)=>{
                    console.error("Error al consultar estudiante", error);
                    alert("Error al consultar");
                });
            },

            actualizar(){
                axios.put(("https://ejemplo3-production-817c.up.railway.app/api/estudiantes/actualizar/"+this.codigo),{
                    codigo: this.codigo,
                    nombre: this.nombre,
                    apellido: this.apellido,
                    edad: this.edad,
                   
                })
                .then((Response)=>{
                    console.log("Estudiante actualizado con éxito", Response.data);
                    alert("El estudiante ha sido actualzido con éxito");
                })
                .catch((error)=>{
                    console.log("Error al actualizar: ", error);
                    alert("Error al actualizar");
                });
            },

            eliminar(){
                axios.delete("https://ejemplo3-production-817c.up.railway.app/api/estudiantes/"+this.codigo)
                .then(() =>{
                    console.log("Estudiante eliminado con éxito");
                    alert("Estudiante eliminado");
                    this.codigo="";
                    this.nombre="";
                    this.apellido="";
                    this.edad="";
                })
                .catch((error)=>{
                    console.log("Error al eliminar estudiante", error);
                    alert("error al eliminar");
                });
            }
        }
    }


</script>
