<template>
    <div class="container">
        <h1>Tabla Estudiantes</h1>

        <table>
            <thead>
                <tr>
                    <th>Código</th>
                    <th>Nombre</th>
                    <th>Apelligo</th>
                    <th>Edad</th>
                </tr>
            </thead>
            <tbody>
                <tr v-for="estudiante in estudiantes" :key="estudiante.codigo" >
                    <td>{{ estudiante.codigo}}</td>
                    <td>{{ estudiante.nombre }}</td>
                    <td>{{ estudiante.apellido }}</td>
                    <td>{{ estudiante.edad}}</td>
                </tr>
                
            </tbody>

        </table>

    </div>
</template>


<script>
import axios from 'axios';

export default{
    data(){
        return{
            estudiantes: [],
        }
    },

    methods:{
        obtenerEstudiantes(){
            axios.get("https://ejemplo3-production-817c.up.railway.app/api/estudiantes/listar")
            .then((Response)=>{
                this.estudiantes = Response.data;
            })
            .catch((error) =>{
                console.error("Error al obtener estudiantes", error);
                alert("error al consultar");
            });

        },

    },
    mounted(){
        this.obtenerEstudiantes();
    }


}

</script>